package com.hogaria.entity;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.util.UUID;
@Entity @Table(name="account",uniqueConstraints=@UniqueConstraint(columnNames={"profile_id","name"})) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class Account { @Id @GeneratedValue private UUID id; @Column(nullable=false) private UUID profileId; @Column(nullable=false) private String name; @Enumerated(EnumType.STRING) @Column(nullable=false) private AccountType accountType; @Column(nullable=false,length=3) private String currency; private BigDecimal creditLimit; private Integer statementCloseDay; private Integer dueDay; @Column(nullable=false) private boolean active; public enum AccountType{CASH,BANK,CREDIT_CARD,DEBIT_CARD,VIRTUAL_WALLET,BUSINESS}}
